package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class GsonFieldNamingStrategyTest {

  @Test
  void testFieldNamingStrategy_Default() throws Exception {
    Gson gson = new Gson();

    // Use reflection to get the private static final DEFAULT_FIELD_NAMING_STRATEGY field from Gson class
    Field field = Gson.class.getDeclaredField("DEFAULT_FIELD_NAMING_STRATEGY");
    field.setAccessible(true);
    FieldNamingStrategy defaultStrategy = (FieldNamingStrategy) field.get(null);

    FieldNamingStrategy strategyFromMethod = gson.fieldNamingStrategy();
    assertNotNull(strategyFromMethod);

    // The default strategy should be FieldNamingPolicy.IDENTITY
    assertEquals(defaultStrategy, strategyFromMethod);
    assertEquals(FieldNamingPolicy.IDENTITY, strategyFromMethod);
  }
}
